	_pToolDiaMultiList = NULL;
	_pAcuteAngleMultiList = NULL;
	_pCtxMenuCritZone = NULL;
	_pCtxMenuSegmentMinDist = NULL;
	_pCtxMenuEdgeVentMinDist = NULL;
	_pCtxMenuToolDia = NULL;
	_pCtxMenuAcuteAngle = NULL;

	_pMainFrame = new CATDlgFrame(this, (const char*)"MainFrame", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
	_pMainFrame->SetGridConstraints(0, 0, 5, 1, CATGRID_4SIDES);

