void MRFVentAnalysisResultDlg::BuildMinimumVentResults(CATListOfCATUnicodeString iListOfVentNames, CATListOfDouble iDistanceList, CATListOfCATUnicodeString iListOfRefVentNames)
{
	int child = _pMainFrame->GetChildCount();

	CATDlgFrame * pMinimumVentFrame = new CATDlgFrame(_pMainFrame, (const char*)"Minimum Vent Distance Analysis KO Results", CATDlgGridLayout);
	pMinimumVentFrame->SetGridConstraints(child,0, 1, 1, CATGRID_4SIDES);

	_pSegmentMinDistMultiList = new CATDlgMultiList(pMinimumVentFrame, (const char*)"MinVentResults");
	_pSegmentMinDistMultiList->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	_pCtxMenuSegmentMinDist = new CATDlgContextualMenu(_pSegmentMinDistMultiList, CATString("CtxMenuMinDistResults"), CATDlgCtxEmpty);

	CATUnicodeString strHeader[4];
	strHeader[0] = "   Vent   ";
	strHeader[1] = "  Status  ";
	strHeader[2] = "Distance";
	strHeader[3] = "Reference Vent";

	_pSegmentMinDistMultiList->SetColumnTitles(4, strHeader);
	_pSegmentMinDistMultiList->SetVisibleColumnCount(4);

	int iSize = iListOfVentNames.Size();
	if (iSize <= 15)
		_pSegmentMinDistMultiList->SetVisibleLineCount(iSize);
	else
		_pSegmentMinDistMultiList->SetVisibleLineCount(15);

	for (int i = 1; i <= iSize; i++)
	{
		CATUnicodeString strVent = iListOfVentNames[i];
		_pSegmentMinDistMultiList->SetColumnItem(0, strVent, i - 1);

		CATUnicodeString strKO = "     KO     ";
		_pSegmentMinDistMultiList->SetColumnItem(1, strKO, i - 1);

		CATUnicodeString strDistance;
		double distance = iDistanceList[i];
		strDistance.BuildFromNum(distance);

		_pSegmentMinDistMultiList->SetColumnItem(2, strDistance, i - 1);

		CATUnicodeString strRefVent = iListOfRefVentNames[i];
		_pSegmentMinDistMultiList->SetColumnItem(3, strRefVent, i - 1);
	}
}

