void MRFVentAnalysisResultDlg::ClearMultiListSelections()
{
	if (NULL != _pCritZoneMultiList)
	{
		_pCritZoneMultiList->ClearSelect();
	}
	if (NULL != _pSegmentMinDistMultiList)
	{
		_pSegmentMinDistMultiList->ClearSelect();
	}
	if (NULL != _pEdgeVentMinDistMultiList)
	{
		_pEdgeVentMinDistMultiList->ClearSelect();
	}
	if (NULL != _pToolDiaMultiList)
	{
		_pToolDiaMultiList->ClearSelect();
	}
	if (NULL != _pAcuteAngleMultiList)
	{
		_pAcuteAngleMultiList->ClearSelect();
	}
}

void MRFVentAnalysisResultDlg::ClearOtherPitchVentResults(CATString istrContext)
{
	if (istrContext == "PitchMinDist")
	{
		if (NULL != _pEdgeVentMinDistMultiList)
			_pEdgeVentMinDistMultiList->ClearSelect();
		if (NULL != _pToolDiaMultiList)
			_pToolDiaMultiList->ClearSelect();
		if (NULL != _pAcuteAngleMultiList)
			_pAcuteAngleMultiList->ClearSelect();
	}
	else if (istrContext == "PitchMinEdgeDist")
	{
		if (NULL != _pSegmentMinDistMultiList)
			_pSegmentMinDistMultiList->ClearSelect();
		if (NULL != _pToolDiaMultiList)
			_pToolDiaMultiList->ClearSelect();
		if (NULL != _pAcuteAngleMultiList)
			_pAcuteAngleMultiList->ClearSelect();
	}
	else if (istrContext == "ToolDiaInterference")
	{
		if (NULL != _pEdgeVentMinDistMultiList)
			_pEdgeVentMinDistMultiList->ClearSelect();
		if (NULL != _pSegmentMinDistMultiList)
			_pSegmentMinDistMultiList->ClearSelect();
		if (NULL != _pAcuteAngleMultiList)
			_pAcuteAngleMultiList->ClearSelect();
	}
	else if (istrContext == "AcuteAngle")
	{
		if (NULL != _pEdgeVentMinDistMultiList)
			_pEdgeVentMinDistMultiList->ClearSelect();
		if (NULL != _pSegmentMinDistMultiList)
			_pSegmentMinDistMultiList->ClearSelect();
		if (NULL != _pToolDiaMultiList)
			_pToolDiaMultiList->ClearSelect();
	}
}

